{
  "operationName": "GetProducts",
  "query": "query GetProducts($filters: ProductListFilters) {
  products(filters: $filters) {
    items {
      id
      slug
      title
      brand
      images { url alt width height }
      variants {
        id sku title attributes
        price { list { amount currency } sale { amount currency } effective { amount currency } }
        inventoryStatus availableQuantity
      }
      defaultVariantId tags updatedAt
    }
    page pageSize totalItems
  }
}",
  "variables": {
    "filters": {
      "category": "women",
      "page": 1,
      "pageSize": 12
    }
  }
}

